### Backend Service Interfaces

```typescript
// packages/sdk/src/types/services.ts

// Auth Service
interface AuthService {
  register(data: RegisterDTO): Promise<{ userId: string; verificationSent: boolean }>;
  login(data: LoginDTO): Promise<TokenPair>;
  refreshToken(refreshToken: string): Promise<TokenPair>;
  verifyEmail(token: string): Promise<void>;
  enableTOTP(userId: string): Promise<{ secret: string; qrCode: string }>;
  verifyTOTP(userId: string, code: string): Promise<boolean>;
  resetPassword(email: string): Promise<void>;
  changePassword(userId: string, data: ChangePasswordDTO): Promise<void>;
}

// Player Service
interface PlayerService {
  getCharacters(userId: string): Promise<Character[]>;
  getInventory(characterId: string, page: number): Promise<PaginatedResult<Item>>;
  transferItem(fromCharId: string, toCharId: string, itemId: string, qty: number): Promise<void>;
  getStatistics(userId: string, period: StatPeriod): Promise<PlayerStats>;
}

// Guild Service
interface GuildService {
  getGuild(guildId: string): Promise<GuildProfile>;
  getMembers(guildId: string, page: number): Promise<PaginatedResult<GuildMember>>;
